svg.script:
let m=0,e=0,bpm=128.000000,s=Date.now();
function a(){
  let t=(Date.now()-s)/1000;
  // Slow the rotation speed down by 8x for a majestic cinematic feel
  m=(t*(bpm/(60*8)))%1; e=(t*(bpm*1.618/(60*8)))%1;
  let hue = (m*360 + 180) % 360;
  document.getElementById('main').setAttribute('stroke',`hsl(${hue},100%,70%)`);
  document.getElementById('echo').setAttribute('transform',`rotate(${e*360} 400 400)`);
  requestAnimationFrame(a);
}
a();
